import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../api/axios';
import Navbar from '../components/Navbar';
import AddEndpointModal from '../components/AddEndpointModal';
import { formatTime } from '../utils/time';

// ── Status pill ────────────────────────────────────────────────────────────────
function StatusPill({ status }) {
  const cls = {
    UP:      'bg-green-100 text-green-800 dark:bg-transparent dark:text-gh-green-em dark:border dark:border-gh-green-em/30',
    DOWN:    'bg-red-100 text-red-700 dark:bg-transparent dark:text-red-400 dark:border dark:border-red-400/30',
    TIMEOUT: 'bg-yellow-100 text-yellow-800 dark:bg-transparent dark:text-yellow-400 dark:border dark:border-yellow-400/30',
    UNKNOWN: 'bg-gray-100 text-gray-500 dark:bg-transparent dark:text-gh-dim dark:border dark:border-gh-dim/30',
  };
  const dotCls = {
    UP: 'bg-green-500 dark:bg-gh-green-em', DOWN: 'bg-red-500', TIMEOUT: 'bg-yellow-500', UNKNOWN: 'bg-gray-400',
  };
  const c = cls[status] || cls.UNKNOWN;
  const d = dotCls[status] || dotCls.UNKNOWN;
  return (
    <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-semibold ${c}`}>
      <span className={`w-1.5 h-1.5 rounded-full ${d}`} />
      {status || 'UNKNOWN'}
    </span>
  );
}

// ── Latency display ────────────────────────────────────────────────────────────
function Latency({ ms }) {
  if (ms == null || ms < 0) return <span className="font-mono text-xs text-gray-400 dark:text-gh-dim">—</span>;
  const cls = ms > 1000
    ? 'text-orange-500 dark:text-orange-400'
    : ms > 500
    ? 'text-yellow-600 dark:text-yellow-400'
    : 'text-green-600 dark:text-gh-green-em';
  return <span className={`font-mono text-xs font-medium ${cls}`}>{ms}ms</span>;
}

// ── Main component ─────────────────────────────────────────────────────────────
export default function Dashboard() {
  const [endpoints, setEndpoints] = useState([]);
  const [histories, setHistories] = useState({});
  const [showModal, setShowModal] = useState(false);
  const [selected, setSelected]   = useState(null);
  const [filter, setFilter]       = useState('');
  const navigate = useNavigate();

  const fetchEndpoints = async () => {
    const { data } = await api.get('/api/endpoints');
    setEndpoints(data);
    return data;
  };

  const fetchHistory = async (ep) => {
    try {
      const { data } = await api.get(`/api/endpoints/${ep.id}/history?hours=24`);
      setHistories(prev => ({ ...prev, [ep.id]: data }));
    } catch (_) {}
  };

  useEffect(() => {
    fetchEndpoints().then(data => data.forEach(ep => fetchHistory(ep)));
  }, []);

  const deleteEndpoint = async (id, e) => {
    e.stopPropagation();
    if (!window.confirm('Delete this endpoint?')) return;
    await api.delete(`/api/endpoints/${id}`);
    setEndpoints(prev => prev.filter(ep => ep.id !== id));
    setHistories(prev => { const n = { ...prev }; delete n[id]; return n; });
    if (selected === id) setSelected(null);
  };

  // ── Derived data ─────────────────────────────────────────────────────────────
  const filteredEndpoints = useMemo(() =>
    endpoints.filter(ep =>
      !filter ||
      ep.name?.toLowerCase().includes(filter.toLowerCase()) ||
      ep.url?.toLowerCase().includes(filter.toLowerCase())
    ), [endpoints, filter]);

  const allChecks = useMemo(() => {
    const rows = [];
    Object.entries(histories).forEach(([epId, checks]) => {
      const ep = endpoints.find(e => e.id === epId);
      if (!ep) return;
      checks.forEach(c => rows.push({ ...c, epName: ep.name || ep.url, epId }));
    });
    return rows.sort((a, b) => new Date(b.checkedAt) - new Date(a.checkedAt));
  }, [histories, endpoints]);

  const visibleChecks = useMemo(() =>
    selected ? allChecks.filter(c => c.epId === selected) : allChecks,
    [allChecks, selected]);

  const globalUptime = useMemo(() => {
    if (!allChecks.length) return null;
    const up = allChecks.filter(c => c.status === 'UP').length;
    return ((up / allChecks.length) * 100).toFixed(1);
  }, [allChecks]);

  const recentErrors = useMemo(() =>
    allChecks.filter(c => c.status === 'DOWN' || c.status === 'TIMEOUT').slice(0, 6),
    [allChecks]);

  const latestStatus = (ep) => {
    const h = histories[ep.id];
    if (!h || !h.length) return 'UNKNOWN';
    return h[h.length - 1].status;
  };

  const uptimePct = (ep) => {
    const h = histories[ep.id] || [];
    if (!h.length) return null;
    return ((h.filter(c => c.status === 'UP').length / h.length) * 100).toFixed(0);
  };

  const uptimeColor = (pct) => {
    if (pct === null) return 'text-gray-400 dark:text-gh-dim';
    const n = parseFloat(pct);
    if (n >= 99) return 'text-green-600 dark:text-gh-green-em';
    if (n >= 95) return 'text-yellow-600 dark:text-yellow-400';
    return 'text-red-500 dark:text-red-400';
  };

  // ── Render ───────────────────────────────────────────────────────────────────
  return (
    <div className="flex flex-col min-h-screen bg-[#f4f5f7] dark:bg-gh-canvas">
      <Navbar />

      <div className="grid flex-1 overflow-hidden" style={{ gridTemplateColumns: '260px 1fr 288px' }}>

        {/* ── LEFT SIDEBAR ─────────────────────────────────────────────────── */}
        <aside className="flex flex-col bg-white dark:bg-gh-default border-r border-gray-200 dark:border-gh-border overflow-y-auto">
          <div className="flex items-center justify-between px-3 py-2.5 border-b border-gray-100 dark:border-gh-border">
            <span className="text-xs font-semibold uppercase tracking-widest text-gray-500 dark:text-gh-muted">Endpoints</span>
            <button
              onClick={() => setShowModal(true)}
              className="flex items-center gap-1 px-2.5 py-1 text-xs font-semibold rounded-lg bg-brand-blue hover:bg-brand-blue-h dark:bg-gh-green dark:hover:bg-gh-green-h text-white transition-colors"
            >
              + New
            </button>
          </div>

          {/* Filter input */}
          <div className="px-3 py-2">
            <div className="relative">
              <svg className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-gray-400 dark:text-gh-dim" fill="none" stroke="currentColor" strokeWidth={2} viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" d="m21 21-4.35-4.35M17 11A6 6 0 1 1 5 11a6 6 0 0 1 12 0z" />
              </svg>
              <input
                value={filter}
                onChange={e => setFilter(e.target.value)}
                placeholder="Filter endpoints…"
                className="w-full pl-8 pr-3 py-1.5 text-xs rounded-xl bg-[#e5e7eb] dark:bg-gh-canvas border border-transparent focus:border-brand-blue dark:focus:border-brand-blue focus:outline-none text-gray-700 dark:text-gh-text placeholder-gray-400 dark:placeholder-gh-dim transition-colors"
              />
            </div>
          </div>

          {/* Endpoint list */}
          <div className="flex-1 overflow-y-auto">
            {filteredEndpoints.length === 0 && (
              <p className="px-3 py-4 text-xs text-gray-400 dark:text-gh-dim">
                {endpoints.length === 0 ? 'No endpoints yet. Click + New.' : 'No matches.'}
              </p>
            )}
            {filteredEndpoints.map(ep => {
              const st = latestStatus(ep);
              const isActive = selected === ep.id;
              const dotCls = { UP: 'bg-green-500', DOWN: 'bg-red-500', TIMEOUT: 'bg-yellow-500', UNKNOWN: 'bg-gray-400' };
              return (
                <div
                  key={ep.id}
                  onClick={() => setSelected(isActive ? null : ep.id)}
                  className={`flex items-start gap-2 px-3 py-2.5 cursor-pointer transition-colors border-l-2 ${
                    isActive
                      ? 'bg-blue-50 dark:bg-gh-subtle border-brand-blue'
                      : 'bg-transparent border-transparent hover:bg-gray-50 dark:hover:bg-gh-subtle'
                  }`}
                >
                  <span className={`w-2 h-2 rounded-full mt-1.5 flex-shrink-0 ${dotCls[st] || 'bg-gray-400'}`} />
                  <div className="flex-1 min-w-0">
                    <p className={`text-xs font-medium truncate ${isActive ? 'text-brand-blue' : 'text-gray-800 dark:text-gh-text'}`}>
                      {ep.name || ep.url}
                    </p>
                    <p className="text-[11px] text-gray-400 dark:text-gh-dim mt-0.5">every {ep.checkIntervalSeconds}s</p>
                  </div>
                  <div className="flex gap-1 flex-shrink-0 opacity-0 group-hover:opacity-100">
                    <button
                      onClick={e => { e.stopPropagation(); navigate(`/endpoints/${ep.id}`); }}
                      className="text-[11px] text-gray-400 hover:text-brand-blue dark:hover:text-brand-blue px-1 py-0.5 rounded"
                    >↗</button>
                    <button
                      onClick={e => deleteEndpoint(ep.id, e)}
                      className="text-[11px] text-gray-400 hover:text-red-500 dark:hover:text-red-400 px-1 py-0.5 rounded"
                    >✕</button>
                  </div>
                </div>
              );
            })}
          </div>
        </aside>

        {/* ── CENTER FEED ───────────────────────────────────────────────────── */}
        <main className="flex flex-col overflow-y-auto bg-[#f4f5f7] dark:bg-gh-canvas px-4 py-4 gap-3">
          {/* Header card */}
          <div className="bg-white dark:bg-gh-default rounded-2xl shadow-sm dark:shadow-none dark:border dark:border-gh-border px-4 py-3 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <span className="text-sm font-semibold text-gray-800 dark:text-gh-text">
                {selected
                  ? `${endpoints.find(e => e.id === selected)?.name || 'Endpoint'} — Checks`
                  : 'Recent Health Checks'}
              </span>
              {selected && (
                <button
                  onClick={() => setSelected(null)}
                  className="text-[11px] text-gray-400 hover:text-gray-700 dark:hover:text-gh-text bg-gray-100 dark:bg-gh-subtle px-2 py-0.5 rounded-full transition-colors"
                >
                  All ✕
                </button>
              )}
            </div>
            <span className="text-[11px] text-gray-400 dark:text-gh-dim bg-gray-100 dark:bg-gh-subtle px-2.5 py-0.5 rounded-full">
              {visibleChecks.length} checks
            </span>
          </div>

          {/* Checks list card */}
          <div className="bg-white dark:bg-gh-default rounded-2xl shadow-sm dark:shadow-none dark:border dark:border-gh-border overflow-hidden flex-1">
            {visibleChecks.length === 0 ? (
              <div className="flex items-center justify-center h-40 text-sm text-gray-400 dark:text-gh-dim">
                No health checks yet
              </div>
            ) : (
              <div className="divide-y divide-gray-50 dark:divide-gh-border">
                {/* Table header */}
                <div className="grid px-4 py-2 bg-gray-50 dark:bg-gh-subtle text-[11px] font-semibold uppercase tracking-wider text-gray-400 dark:text-gh-dim" style={{ gridTemplateColumns: '100px 1fr 80px 130px' }}>
                  <span>Status</span>
                  <span>Endpoint</span>
                  <span>Latency</span>
                  <span>Time</span>
                </div>
                {visibleChecks.slice(0, 100).map((c, i) => (
                  <div
                    key={i}
                    onClick={() => navigate(`/endpoints/${c.epId}`)}
                    className="grid items-center px-4 py-2.5 hover:bg-gray-50 dark:hover:bg-gh-subtle cursor-pointer transition-colors"
                    style={{ gridTemplateColumns: '100px 1fr 80px 130px' }}
                  >
                    <StatusPill status={c.status} />
                    <span className="text-xs font-medium text-gray-700 dark:text-gh-text truncate pr-3">{c.epName}</span>
                    <Latency ms={c.latencyMs} />
                    <span className="text-[11px] text-gray-400 dark:text-gh-dim">{formatTime(c.checkedAt)}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </main>

        {/* ── RIGHT SIDEBAR ─────────────────────────────────────────────────── */}
        <aside className="flex flex-col gap-3 p-4 overflow-y-auto bg-[#f4f5f7] dark:bg-gh-canvas border-l border-gray-200 dark:border-gh-border">

          {/* System Overview card */}
          <div className="bg-white dark:bg-gh-default rounded-2xl shadow-sm dark:shadow-none dark:border dark:border-gh-border p-4">
            <h3 className="text-xs font-semibold uppercase tracking-widest text-gray-400 dark:text-gh-muted mb-3">System Overview</h3>

            {/* Global Uptime */}
            <div className="flex items-center justify-between p-3 rounded-xl bg-gray-50 dark:bg-gh-canvas mb-2">
              <span className="text-xs text-gray-600 dark:text-gh-muted">Global Uptime (24h)</span>
              <span className={`text-base font-bold ${uptimeColor(globalUptime)}`}>
                {globalUptime !== null ? `${globalUptime}%` : '—'}
              </span>
            </div>

            {/* Active Endpoints */}
            <div className="flex items-center justify-between p-3 rounded-xl bg-gray-50 dark:bg-gh-canvas">
              <span className="text-xs text-gray-600 dark:text-gh-muted">Active Endpoints</span>
              <span className="text-base font-bold text-gray-800 dark:text-gh-text">{endpoints.length}</span>
            </div>
          </div>

          {/* Per-endpoint uptime card */}
          {endpoints.length > 0 && (
            <div className="bg-white dark:bg-gh-default rounded-2xl shadow-sm dark:shadow-none dark:border dark:border-gh-border p-4">
              <h3 className="text-xs font-semibold uppercase tracking-widest text-gray-400 dark:text-gh-muted mb-3">Endpoint Health</h3>
              <div className="space-y-2">
                {endpoints.map(ep => {
                  const st  = latestStatus(ep);
                  const pct = uptimePct(ep);
                  const dotCls = { UP: 'bg-green-500', DOWN: 'bg-red-500', TIMEOUT: 'bg-yellow-500', UNKNOWN: 'bg-gray-400' };
                  return (
                    <div key={ep.id} className="flex items-center gap-2">
                      <span className={`w-2 h-2 rounded-full flex-shrink-0 ${dotCls[st] || 'bg-gray-400'}`} />
                      <span className="flex-1 text-xs text-gray-600 dark:text-gh-muted truncate">{ep.name || ep.url}</span>
                      <span className={`text-xs font-semibold ${uptimeColor(pct)}`}>
                        {pct !== null ? `${pct}%` : '—'}
                      </span>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* Recent Errors card */}
          <div className="bg-white dark:bg-gh-default rounded-2xl shadow-sm dark:shadow-none dark:border dark:border-gh-border p-4">
            <div className="flex items-center justify-between mb-3">
              <h3 className="text-xs font-semibold uppercase tracking-widest text-gray-400 dark:text-gh-muted">Recent Errors</h3>
              {recentErrors.length > 0 && (
                <span className="text-[11px] font-semibold px-2 py-0.5 rounded-full bg-red-100 text-red-600 dark:bg-transparent dark:text-red-400 dark:border dark:border-red-400/30">
                  {recentErrors.length}
                </span>
              )}
            </div>

            {recentErrors.length === 0 ? (
              <div className="flex items-center gap-1.5 py-1">
                <span className="w-1.5 h-1.5 rounded-full bg-green-500" />
                <span className="text-xs text-gray-400 dark:text-gh-dim">No recent errors</span>
              </div>
            ) : (
              <div className="space-y-2">
                {recentErrors.map((c, i) => (
                  <div
                    key={i}
                    onClick={() => navigate(`/endpoints/${c.epId}`)}
                    className="flex items-start gap-2 cursor-pointer group"
                  >
                    <StatusPill status={c.status} />
                    <div className="flex-1 min-w-0">
                      <p className="text-xs font-medium text-gray-700 dark:text-gh-text truncate group-hover:text-brand-blue transition-colors">{c.epName}</p>
                      <p className="text-[11px] text-gray-400 dark:text-gh-dim">{formatTime(c.checkedAt)}</p>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </aside>
      </div>

      {showModal && (
        <AddEndpointModal
          onClose={() => setShowModal(false)}
          onAdded={ep => {
            setEndpoints(prev => [...prev, ep]);
            fetchHistory(ep);
          }}
        />
      )}
    </div>
  );
}
